solution_code:
module seq1011(input clk, rst_n, x, output found);
  localparam S0=0,S1=1,S10=2,S101=3;
  reg [1:0] st;
  always @(posedge clk or negedge rst_n)
    if(!rst_n) st<=S0;
    else case(st)
      S0:  st <= x?S1:S0;
      S1:  st <= x?S1:S10;
      S10: st <= x?S101:S0;
      S101:st <= x?S1:S10;
    endcase
  assign found = (st==S101) & x;
endmodule

