solution_code:
module prio_enc #(parameter WIDTH=8)(input logic [WIDTH-1:0] in, output logic [$clog2(WIDTH)-1:0] idx, output logic valid);
  always_comb begin
    idx = '0; valid = 1'b0;
    for (int i=0;i<WIDTH;i++) if (in[i]) begin idx=i[$clog2(WIDTH)-1:0]; valid=1'b1; end
  end
endmodule

